<template><main class="container py-5"><header class="mb-4"><span class="eyebrow">CARSTORE</span><h1>Tin tức ô tô</h1></header><div v-if="loading" class="text-center py-5">Đang tải...</div><div v-else class="news-grid"><article v-for="item in articles" :key="item.id" class="news-card"><img v-if="item.thumbnail" :src="carImageUrl(item.thumbnail)" :alt="item.title"><div><small>{{ formatDate(item.createdAt) }}</small><h2>{{ item.title }}</h2><p>{{ item.summary }}</p><router-link :to="`/news/${item.slug}`">Đọc chi tiết</router-link></div></article></div><p v-if="!loading&&!articles.length" class="text-center py-5">Chưa có tin tức.</p></main></template>
<script setup>import{onMounted,ref}from'vue';import{newsApi,carImageUrl}from'../api';const articles=ref([]),loading=ref(true),formatDate=v=>v?new Date(v).toLocaleDateString('vi-VN'):'';onMounted(async()=>{try{const{data}=await newsApi.getPublished();articles.value=data.data||[]}finally{loading.value=false}})</script>
<style scoped>.eyebrow{color:#b91c1c;font-weight:800}.news-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:22px}.news-card{overflow:hidden;border:1px solid #e5e7eb;border-radius:14px;background:#fff}.news-card img{width:100%;height:210px;object-fit:cover}.news-card div{padding:20px}.news-card small{color:#6b7280}.news-card h2{font-size:1.2rem;font-weight:800;margin:8px 0}.news-card p{color:#6b7280}@media(max-width:850px){.news-grid{grid-template-columns:1fr}}</style>
